// Find the PDF binary field in the incoming request
const item = $input.first();
const binaryKeys = Object.keys(item.binary || {});
const pdfKey = binaryKeys.find(k => {
  const mime = item.binary[k].mimeType || '';
  const name = (item.binary[k].fileName || '').toLowerCase();
  return mime === 'application/pdf' || name.endsWith('.pdf');
}) || binaryKeys[0];

if (!pdfKey) throw new Error('No PDF found in upload');

return [{
  json: {
    ...item.json,
    _pdfBinaryKey: pdfKey,
    _fileName: item.binary[pdfKey].fileName || 'resume.pdf'
  },
  binary: item.binary
}];

